  ('diplomatic-456f2445-moex-00132', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-113-10317cea', 'sub-diplomatic-456f2445-02', NULL, 'essay', '依據 1982年《聯合國海洋法公約》（1982 United Nations Convention on
theLawoftheSea）的規定，試從海盜之定義分析締約國於公海上對海盜
行為予以扣押船舶之權力及其限制。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:19+00:00", "source_pdf_sha1": "fce0585a3133", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國際公法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL),
  ('diplomatic-456f2445-moex-00133', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-113-10317cea', 'sub-diplomatic-456f2445-02', NULL, 'essay', '世界貿易組織（WorldTrade Organization）成立至今約 30年，爭端解決
機制中的上訴機構運作瀕臨停擺，WTO部分會員提出「多方臨時上訴仲
裁協議」（Multi-PartyInterimAppealArbitrationArrangement，MPIA）作
為上訴機構之臨時替代方案，試申論 WTO 爭端解決機制引發那些爭
議？又 MPIA之目的與程序為何？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:19+00:00", "source_pdf_sha1": "fce0585a3133", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國際公法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL),
  ('diplomatic-456f2445-moex-00134', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-113-10317cea', 'sub-diplomatic-456f2445-02', NULL, 'essay', '國際法上的管轄權（jurisdiction）主要由國家所行使之，而關於國家的「域
外管轄」（extraterritorialjurisdiction）則時常產生爭議。試舉例說明並解
釋「域外管轄」所保護之利益及其可能與國際法衝突之處。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:19+00:00", "source_pdf_sha1": "fce0585a3133", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國際公法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL),
  ('diplomatic-456f2445-moex-00135', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-113-10317cea', 'sub-diplomatic-456f2445-02', NULL, 'single_choice', '依據維也納條約法公約，關於條約的解釋，下列敘述何者錯誤？', '["條約應以善意解釋之", "條約應按其上下文並參考其目的及宗旨解釋所具有之特殊意義解釋", "就解釋條約而言，上下文應包括弁言及附件", "就解釋條約而言，上下文應包括全體當事國間因締結條約所訂與條約有關之任何協定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:19+00:00", "source_pdf_sha1": "fce0585a3133", "answer_pdf_sha1": "3769d2d2ee5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL),
  ('diplomatic-456f2445-moex-00136', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-113-10317cea', 'sub-diplomatic-456f2445-02', NULL, 'single_choice', '關於1969年維也納條約法公約規定，下列敘述何者錯誤？', '["依維也納條約法公約第 26 條之規定，凡有效之條約對其各當事國有拘束力，必須由各該國善 意履行", "依維也納條約法公約第 27 條規定，若有國內管轄原則之適用時，一當事國得援引其國內法規 定為理由而不履行條約", "依維也納條約法公約第28條之規定，除條約表示不同意思，或另經確定外，關於條約對一當事 國生效之日以前所發生之任何行為或事實或已不存在之任何情勢，條約之規定不對該當事國發 生拘束力", "依維也納條約法公約第29條之規定，除條約表示不同意思，或另經確定外，條約對每一當事國 之拘束力及於其全部領土"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:19+00:00", "source_pdf_sha1": "fce0585a3133", "answer_pdf_sha1": "3769d2d2ee5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL),
  ('diplomatic-456f2445-moex-00137', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-113-10317cea', 'sub-diplomatic-456f2445-02', NULL, 'single_choice', '關於國際法主體，下列敘述何者正確？', '["政府間國際組織已成為最重要的國際法主體", "非自治領土均非國際法主體", "個人一定不是國際法主體", "民族解放運動得為國際法主體"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:19+00:00", "source_pdf_sha1": "fce0585a3133", "answer_pdf_sha1": "3769d2d2ee5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL),
  ('diplomatic-456f2445-moex-00138', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-113-10317cea', 'sub-diplomatic-456f2445-02', NULL, 'single_choice', '下列何者並非現存區域性人權條約所設之區域人權法院？', '["歐洲人權法院（EuropeanCourtofHumanRights）", "美洲人權法院（Inter-AmericanCourtofHumanRights）", "非洲人權和人民權利法院（AfricanCourtonHumanandPeople''sRights）", "亞洲人權法院（AsianCourtofHumanRights）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:19+00:00", "source_pdf_sha1": "fce0585a3133", "answer_pdf_sha1": "3769d2d2ee5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL),
  ('diplomatic-456f2445-moex-00139', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-113-10317cea', 'sub-diplomatic-456f2445-02', NULL, 'single_choice', '依據國際法院規約第 38 條第 1 項規定，司法裁判為確定法律原則之補助資料。下列敘述何者正 確？', '["國際法院之裁判具有拘束所有國家之普遍效力", "國際法院規約第38條第1項規定之司法裁判係指國際爭端解決機制之裁決", "國際法院規約第38條第1項規定之司法裁判也包括國內法院裁判", "國際法院規約第38條第1項規定之司法裁判係指國際法院本身之判決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:19+00:00", "source_pdf_sha1": "fce0585a3133", "answer_pdf_sha1": "3769d2d2ee5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL),
  ('diplomatic-456f2445-moex-00140', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-113-10317cea', 'sub-diplomatic-456f2445-02', NULL, 'single_choice', '依聯合國海洋法公約，有關船舶於不同海域所享有之不同程度之航行權，下列敘述何者正確？', '["通過領海之過境通過權", "通過群島國專屬經濟區之群島海道通過權", "通過鄰接區之無害通過權", "通過專屬經濟區之航行自由"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:19+00:00", "source_pdf_sha1": "fce0585a3133", "answer_pdf_sha1": "3769d2d2ee5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL),
  ('diplomatic-456f2445-moex-00141', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-113-10317cea', 'sub-diplomatic-456f2445-02', NULL, 'single_choice', '依聯合國海洋法公約第27條規定：「沿海國不應在通過領海的外國船舶上行使刑事管轄權，以逮 捕與在該船舶通過期間船上所犯任何罪行有關的任何人或進行與該罪行有關的任何調查」，下列 何者並非該條明定之例外？', '["倘若罪行的後果及於沿海國", "罪行屬於擾亂當地安寧或領海的良好秩序的性質", "倘若經沿岸國當地法院下令進行調查或審判", "倘若這些措施是取締違法販運麻醉藥品或精神調理物質所必要的"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:19+00:00", "source_pdf_sha1": "fce0585a3133", "answer_pdf_sha1": "3769d2d2ee5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL)
